={
  "model": "{{ $env.CLAUDE_MODEL || 'claude-opus-4-8' }}",
  "max_tokens": 3000,
  "system": "You are a scriptwriter for short security-awareness videos. For the given topic, audience and target length (seconds) write a SINGLE valid JSON object for a script and storyboard. Keys: title; hook (one punchy opening line, max ~12 words); scenes (4-7 items in order, each {visual (one sentence describing what is on screen), voiceover (1-2 short narration sentences), onScreen (short on-screen caption/text, max ~8 words), seconds (approx duration as a number)}); cta (one closing call-to-action line); takeaways (3-4 short 'lessons learned' one-liners summarising what the viewer should remember). The total of the scene seconds should be close to the target length. Plain, engaging, non-technical language tailored to the audience; one clear behaviour change. Do NOT use markdown code fences. Output ONLY the JSON object.",
  "messages": [ {"role":"user","content": {{ JSON.stringify('Write a short security-awareness video script and storyboard on the topic: ' + ($json.topic || 'phishing') + '. Audience: ' + ($json.audience||'All staff') + '. Target length: ' + ($json.length||90) + ' seconds.') }} } ]
}

