const j = $json || {};
let raw = '';
if (j.message && j.message.content) raw = j.message.content;
else if (j.content && j.content[0] && j.content[0].text) raw = j.content[0].text;
let data = null;
try { data = JSON.parse(raw.replace(/^```(?:json)?\s*/i,'').replace(/\s*```$/i,'')); }
catch (e) { try { const m = raw.match(/\{[\s\S]*\}/); if (m) data = JSON.parse(m[0]); } catch (e2) { data = null; } }
const r = $('Resolve Input').first().json || {};
return [{ json: Object.assign({}, r, { data: data }) }];

// Generate one storyboard FRAME image per scene with the shared image provider
// (gpt-image-2). Images are written to a temp work dir on disk and only file paths
// are set on each scene — never base64 — so n8n execution data stays tiny (same
// hardened pattern as the comic/magazine). Graceful: scenes whose image fails keep
// the styled gradient frame.
const fs = require('fs');
const H = this.helpers;
const r = $json || {};
const d = r.data || {};
const A = function (x) { return Array.isArray(x) ? x : []; };
const scenes = A(d.scenes);
const key = $env.OPENAI_IMAGE_API_KEY || $env.OPENAI_API_KEY;
const want = (($env.VIDEO_FRAME_IMAGES || $env.CYBER_SECTION_IMAGES || 'true').toString().toLowerCase() !== 'false');
const baseu = ($env.OPENAI_BASE_URL || 'https://api.openai.com/v1');
const model = ($env.IMAGE_MODEL || 'gpt-image-1');
const QV = { low:1, medium:1, high:1, auto:1 };
let quality = String($env.VIDEO_IMAGE_QUALITY || $env.COMIC_IMAGE_QUALITY || 'medium').toLowerCase(); if (!QV[quality]) quality = 'medium';
let conc = parseInt($env.IMAGE_CONCURRENCY || '3', 10); if (!(conc > 0)) conc = 3; if (conc > 8) conc = 8;
let timeout = parseInt($env.IMAGE_TIMEOUT || '120000', 10); if (!(timeout > 0)) timeout = 120000;

const baseName = (r.fileSafe || 'storyboard') + '-' + (r.date || new Date().toISOString().slice(0, 10));
const workDir = '/reports/awareness/video/.work/' + baseName;
try { fs.mkdirSync(workDir, { recursive: true }); } catch (e) {}

const STYLE = 'Cinematic film still for a corporate security-awareness video: semi-realistic, modern office setting, diverse professionals, soft natural light, teal and deep-navy colour grade, 16:9 composition. ';
const NEG = ' No text, no words, no letters, no subtitles, no captions, no logos, no watermark, no UI.';

async function mapLimit(items, limit, fn) {
  const ret = new Array(items.length); let idx = 0;
  async function worker() { while (idx < items.length) { const cur = idx++; ret[cur] = await fn(items[cur], cur); } }
  const n = Math.max(1, Math.min(limit, items.length));
  const workers = []; for (let w = 0; w < n; w++) workers.push(worker());
  await Promise.all(workers);
  return ret;
}
async function gen(prompt) {
  const resp = await H.httpRequest({ method: 'POST', url: baseu + '/images/generations',
    headers: { Authorization: 'Bearer ' + key, 'Content-Type': 'application/json' },
    body: { model: model, prompt: prompt, size: '1536x1024', quality: quality, n: 1 }, json: true, timeout: timeout });
  return resp && resp.data && resp.data[0] && resp.data[0].b64_json;
}

let ok = 0, failed = 0;
if (want && key && scenes.length) {
  const res = await mapLimit(scenes, conc, async function (s, k) {
    let file = '';
    try {
      const b64 = await gen(STYLE + (s.visual || ('Scene ' + (k + 1) + ' about ' + (r.topic || 'security awareness'))) + NEG);
      if (b64) { file = workDir + '/scene-' + String(k + 1).padStart(2, '0') + '.png'; fs.writeFileSync(file, Buffer.from(b64, 'base64')); ok++; }
      else failed++;
    } catch (e) { failed++; }
    return { k: k, file: file };
  });
  res.forEach(function (x) { if (x.file && scenes[x.k]) scenes[x.k].image = x.file; });
}

return [{ json: Object.assign({}, r, { data: d, workDir: workDir, imagesGenerated: ok, imagesFailed: failed }) }];

function jbHex(v,d){v=String(v||'').trim();return /^#[0-9a-fA-F]{6}$/.test(v)?v:d;}
var JB_PRI=jbHex($env.BRAND_PRIMARY,'#0A1A2F'),JB_ACC=jbHex($env.BRAND_ACCENT,'#0E7C86'),JB_GOLD=jbHex($env.BRAND_GOLD,'#E7C76A');
var JB_ROOT=":root{--jb-pri:"+JB_PRI+";--jb-acc:"+JB_ACC+";--jb-gold:"+JB_GOLD+"}";
/* --- Jarvis brand kit (shared across awareness PDFs): avatar + takeaways box + sign-off --- */
var __jfs=null; try{__jfs=require('fs');}catch(e){}
function jAvatarUri(){ if(!__jfs) return ''; var t=[['/config/branding/jarvis-avatar.png','image/png'],['/config/branding/jarvis-avatar.jpg','image/jpeg'],['/config/branding/jarvis-avatar.jpeg','image/jpeg'],['/config/branding/jarvis-avatar.svg','image/svg+xml']]; for(var i=0;i<t.length;i++){ try{ return 'data:'+t[i][1]+';base64,'+__jfs.readFileSync(t[i][0]).toString('base64'); }catch(e){} } return ''; }
var JKIT_SVG='<svg class="jav" viewBox="0 0 64 64" xmlns="http://www.w3.org/2000/svg"><defs><linearGradient id="jkitg" x1="0" y1="0" x2="0" y2="1"><stop offset="0" stop-color="#0E7C86"/><stop offset="1" stop-color="#0A1A2F"/></linearGradient></defs><circle cx="32" cy="32" r="32" fill="url(#jkitg)"/><rect x="19" y="21" width="26" height="22" rx="7" fill="#fff"/><circle cx="27" cy="32" r="3.2" fill="#0E7C86"/><circle cx="37" cy="32" r="3.2" fill="#0E7C86"/><rect x="27" y="38" width="10" height="2.4" rx="1.2" fill="#0E7C86"/><rect x="30.7" y="14" width="2.6" height="6" rx="1.3" fill="#9fe4d8"/><circle cx="32" cy="13" r="2.4" fill="#E7C76A"/><path d="M23 47h18l-3 4.5H26z" fill="#9fe4d8"/></svg>';
var JKIT_CSS=".jkit-take{background:#F4F6F9;border:1px solid #E2E6EC;border-left:4px solid var(--jb-acc);border-radius:10px;padding:14px 18px;margin:22px 0 0;page-break-inside:avoid}.jkit-take .th{font-family:-apple-system,'Segoe UI',Arial,sans-serif;font-size:11px;letter-spacing:2px;text-transform:uppercase;color:var(--jb-pri);font-weight:800;margin:0 0 7px}.jkit-take ul{margin:0;padding-left:18px}.jkit-take li{font-size:13.5px;line-height:1.5;color:#2b3340;margin:5px 0}.jkit-sign{display:flex;align-items:center;gap:12px;margin:20px 0 0;padding-top:14px;border-top:2px solid var(--jb-acc);page-break-inside:avoid}.jkit-sign img,.jkit-sign .jav{width:46px;height:46px;border-radius:50%;border:2px solid var(--jb-acc);flex:0 0 auto}.jkit-sign .nm{font-family:Georgia,serif;font-size:15px;color:var(--jb-pri);font-weight:700}.jkit-sign .rl{font-family:-apple-system,'Segoe UI',Arial,sans-serif;font-size:10px;letter-spacing:2px;text-transform:uppercase;color:var(--jb-acc);font-weight:800;margin-top:2px}";
function jKitEsc(s){ return (s==null?'':String(s)).replace(/[&<>]/g,function(c){return({'&':'&amp;','<':'&lt;','>':'&gt;'})[c];}); }
function jTakeBox(takeaways){ var t=(takeaways||[]).filter(Boolean).slice(0,4); if(!t.length) return ''; return '<div class="jkit-take"><div class="th">Key takeaways &middot; Lessons learned</div><ul>'+t.map(function(x){return '<li>'+jKitEsc(x)+'</li>';}).join('')+'</ul></div>'; }
function jSignoff(){ var av=jAvatarUri(); var avatar=av?('<img src="'+av+'"/>'):JKIT_SVG; return '<div class="jkit-sign">'+avatar+'<div><div class="nm">Jarvis</div><div class="rl">Your AI Awareness Assistant</div></div></div>'; }
function jKitBlock(takeaways){ return jTakeBox(takeaways)+jSignoff(); }

const r = $json || {};
const d = r.data || {};
const topic = r.topic || 'Security Awareness';
const client = (r.client || '').toString();
const brand = client ? client : 'Security Awareness';
const length = r.length || 90;
function esc(s){ return (s==null?'':String(s)).replace(/[&<>]/g,function(c){return({'&':'&amp;','<':'&lt;','>':'&gt;'})[c];}); }
function arr(x){ return Array.isArray(x)?x:(x==null||x===''?[]:[x]); }
const title = d.title || (topic + ' — Awareness Video');
const scenes = arr(d.scenes);
// Scene frames arrive as on-disk file paths (from Generate Frames) — read each one
// lazily and inline it only at render time, so images never travel through node JSON.
function imgSrc(p){ if(!p) return ''; var s=String(p); if(s.indexOf('data:')===0) return s; if(__jfs){ try{ return 'data:image/png;base64,'+__jfs.readFileSync(s).toString('base64'); }catch(e){} } return ''; }
const CSS = JB_ROOT+"@page{size:A4;margin:14mm} *{box-sizing:border-box} body{margin:0;font-family:-apple-system,'Segoe UI',Arial,sans-serif;color:#14202b} "
+".hd{border-bottom:3px solid var(--jb-acc);padding-bottom:10px;margin-bottom:14px} .hd .k{color:var(--jb-acc);letter-spacing:3px;font-size:12px;font-weight:800;text-transform:uppercase} "
+".hd h1{margin:4px 0 0;font-size:25px;color:var(--jb-pri)} .hd .s{color:#5A6472;font-size:13px;margin-top:4px} "
+".hook{background:#F1F7F8;border-left:4px solid var(--jb-acc);border-radius:6px;padding:12px 16px;margin:0 0 16px;font-size:15px;font-style:italic;color:var(--jb-pri)} "
+".sc{display:flex;gap:14px;border:1px solid #e2e6ec;border-radius:8px;padding:12px 14px;margin:0 0 12px;page-break-inside:avoid} "
+".sc .frame{flex:0 0 200px;height:112px;border-radius:6px;overflow:hidden;background:var(--jb-pri);background-size:cover;background-position:center;border:1px solid var(--jb-pri)} "
+".sc .frame.ph{background:linear-gradient(135deg,var(--jb-pri),var(--jb-acc));color:#fff;display:flex;align-items:flex-end;padding:8px;font-size:11px;line-height:1.3} "
+".sc .body{flex:1} .sc .n{font-weight:800;color:var(--jb-acc);font-size:12px} .sc .vo{font-size:14px;line-height:1.5;color:#2b3340;margin:4px 0} "
+".sc .os{display:inline-block;background:var(--jb-pri);color:#fff;border-radius:4px;padding:3px 8px;font-size:11px;margin-top:4px} .sc .t{float:right;color:#8a98a4;font-size:11px} "
+".cta{margin-top:8px;background:var(--jb-pri);color:#fff;border-radius:8px;padding:14px 16px;font-size:15px;font-weight:700} "
+".foot{margin-top:14px;border-top:1px solid #e2e6ec;padding-top:8px;color:#8a98a4;font-size:10px;display:flex;justify-content:space-between}"+JKIT_CSS;
let cards = scenes.map(function(s,k){
  var uri = imgSrc(s.image);
  var frame = uri ? ('<div class="frame" style="background-image:url('+uri+')"></div>') : ('<div class="frame ph">'+esc(s.visual||('Scene '+(k+1)))+'</div>');
  return '<div class="sc">'+frame+'<div class="body">'
    +'<div class="n">SCENE '+(k+1)+(s.seconds?'<span class="t">~'+esc(s.seconds)+'s</span>':'')+'</div>'
    +'<div class="vo"><b>VO:</b> '+esc(s.voiceover||'')+'</div>'
    +(s.onScreen?'<span class="os">'+esc(s.onScreen)+'</span>':'')+'</div></div>';
}).join('');
const html = '<!doctype html><html><head><meta charset="utf-8"><style>'+CSS+'</style></head><body>'
+'<div class="hd"><div class="k">Video Script &amp; Storyboard</div><h1>'+esc(title)+'</h1>'
+'<div class="s">'+esc(brand)+' · Audience: '+esc(r.audience||'All staff')+' · Target length: '+length+'s · '+scenes.length+' scenes</div></div>'
+(d.hook?'<div class="hook">“'+esc(d.hook)+'”</div>':'')
+cards
+(d.cta?'<div class="cta">Call to action: '+esc(d.cta)+'</div>':'')
+jKitBlock(d.takeaways||d.keyMessages)
+'<div class="foot"><span>'+esc(brand)+' · AI-generated script — review before production</span><span>'+esc(r.date)+'</span></div></body></html>';
// Frames are now baked into the HTML — remove the temp work dir (guard: /.work/).
if (r.workDir && r.workDir.indexOf('/.work/') >= 0 && __jfs) { try { __jfs.rmSync(r.workDir, { recursive: true, force: true }); } catch (e) {} }
// Emit the HTML as BINARY for Gotenberg (keeps execution data tiny); small JSON.
const _bin = await this.helpers.prepareBinaryData(Buffer.from(html, 'utf8'), 'index.html', 'text/html');
return [{ json: { topic: topic, date: r.date, fileSafe: r.fileSafe, outDir: 'video', filePrefix: 'storyboard' }, binary: { data: _bin } }];

const fs = require('fs');
const meta = $('Render HTML').first().json;
const dir = '/reports/awareness/' + (meta.outDir || 'misc');
const name = (meta.filePrefix || 'asset') + '-' + (meta.fileSafe || 'item') + '-' + meta.date + '.pdf';
let buf = null;
try { buf = await this.helpers.getBinaryDataBuffer(0, 'data'); } catch (e) {}
try { fs.mkdirSync(dir, { recursive: true }); if (buf) fs.writeFileSync(dir + '/' + name, buf); } catch (e) {}
const out = { json: { ok: !!buf, file: dir + '/' + name, topic: meta.topic } };
try { const b = $input.first().binary; if (b && b.data) { b.data.fileName = name; out.binary = { data: b.data }; } } catch (e) {}
return [out];
